    "id": "s6",
    "num": "S6",
    "title": "Eval 与 Red Team",
    "meta": "Golden · Trajectory · Security",
    "src": "agent-runtime-gateway/02-阶段教学手册/Phase-07-测评审核与红队教学手册.md",
