    "id": "mcp",
    "num": "专题",
    "title": "MCP 与工具生态",
    "meta": "协议 · 准入 · 凭据边界",
    "src": "agent-runtime-gateway/02-阶段教学手册/Phase-05-MCP与工具生态教学手册.md",
